 51→function corsHeaders(
 52→	origin: string | null,
 53→	allowedOrigin: string,
 54→): Record<string, string> {
 55→	if (origin !== allowedOrigin) return {};
 56→	return {
 57→		"Access-Control-Allow-Origin": allowedOrigin,
 58→		"Access-Control-Allow-Credentials": "true",
 59→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 60→		"Access-Control-Allow-Headers": "Content-Type, Authorization",
 61→	};
 62→}
